INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00913', 'judicial-57f41407', 'judicial-57f41407-moex-110-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲向乙購買一筆土地，惟遲至22年後始請求乙將該土地所有權移轉登記於自己。下列敘述，何者正確？', '["乙得以甲之債權因時效完成而消滅為由，拒絕移轉該土地之所有權登記於甲", "如果乙將該土地所有權移轉登記於甲，乙得以其不知時效完成為理由，請求返還土地", "甲依買賣契約得請求乙交付並移轉所有權登記，該土地請求權之消滅時效期間，為20年", "如果乙明知時效完成而承認債務，其後即不得以時效完成為由，拒絕移轉所有權登記該土地於甲"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "160e5bc9c84a", "answer_pdf_sha1": "7aed6d4ac3f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00914', 'judicial-57f41407', 'judicial-57f41407-moex-110-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '依民法第767條第1項規定，所有人對於無權占有或侵奪其所有物者，得請求返還之。下列何者為無權占有？', '["質權人因合法之質權設定占有質物", "不動產買受人自行占有買賣之不動產", "受贈人因贈與人交付而占有贈與之不動產", "出賣人移轉買賣之不動產所有權於買受人後，仍占有該不動產"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "160e5bc9c84a", "answer_pdf_sha1": "7aed6d4ac3f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00915', 'judicial-57f41407', 'judicial-57f41407-moex-110-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '最高限額抵押權之行使，以其所擔保債權之確定為前提。下列何者並非最高限額抵押權所擔保債權之確定 方法？', '["約定之原債權確定期日屆至", "最高限額抵押權所擔保之債權消滅", "最高限額抵押權人聲請裁定拍賣抵押物", "擔保債權所由發生之法律關係經終止"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "160e5bc9c84a", "answer_pdf_sha1": "7aed6d4ac3f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00916', 'judicial-57f41407', 'judicial-57f41407-moex-110-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲有二手車A車一輛，欲以新臺幣（下同）10萬元出售，詢問乙有無意願購買。乙聞訊後，即向甲表示 自己雖很喜歡A車，但預算有限，若是8萬元就買。下列敘述，何者正確？', '["甲問乙是否願意以10萬元購買A車，為要約之引誘", "乙回答若是8萬元就買，依民法第160條第2項規定，推定為新要約", "乙回答若是8萬元就買時，甲乙間已成立A車之買賣契約", "甲若拒絕以8萬元出售A車，則乙之要約失去拘束力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "160e5bc9c84a", "answer_pdf_sha1": "7aed6d4ac3f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00917', 'judicial-57f41407', 'judicial-57f41407-moex-110-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲向乙購買書，回家後發現該書有缺頁之問題。關於乙之給付行為，下列敘述，何者正確？', '["給付不能", "給付遲延", "權利瑕疵", "不完全給付"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "160e5bc9c84a", "answer_pdf_sha1": "7aed6d4ac3f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00918', 'judicial-57f41407', 'judicial-57f41407-moex-110-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '依現行民法規定，下列關於結婚效力之敘述，何者正確？', '["代理結婚者，結婚為得撤銷", "經法院公證結婚者，結婚即為有效", "違反近親結婚禁止之規定者，結婚為無效", "有配偶者重婚，重婚為得撤銷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "160e5bc9c84a", "answer_pdf_sha1": "7aed6d4ac3f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00919', 'judicial-57f41407', 'judicial-57f41407-moex-110-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '下列關於證據能力之敘述，何者正確？', '["證據能力係指證據能否證明犯罪之程度", "警察違法搜索取得之證據，當然沒有證據能力", "被告一旦自白，即可判決有罪，不須進行其他的證據調查", "被告之自白，若是出於脅迫之方法，不得作為證據"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "160e5bc9c84a", "answer_pdf_sha1": "7aed6d4ac3f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00920', 'judicial-57f41407', 'judicial-57f41407-moex-110-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲喪偶有一子丙，乙喪偶有一子丁。甲、乙為兄弟。乙死亡時未留財產，丁年僅10歲，甲扶養丁。5年後， 甲亦死亡。甲死亡時，留有財產，丁對甲之遺產得主張何種權利？', '["繼承權", "遺贈交付請求權", "遺產酌給請求權", "遺產分割請求權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "160e5bc9c84a", "answer_pdf_sha1": "7aed6d4ac3f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00921', 'judicial-57f41407', 'judicial-57f41407-moex-110-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '依現行實務見解，法院關於下列何者之認定，不適用刑事訴訟法之嚴格證明法則？', '["貪污案件之被告是否具備公務員身分", "妨害性自主罪之被害人是否已滿14歲", "過失致人於死案件中被告駕車不慎行為與被害人死亡結果之因果關係", "普通詐欺案件中被告之犯罪所得範圍"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "160e5bc9c84a", "answer_pdf_sha1": "7aed6d4ac3f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00922', 'judicial-57f41407', 'judicial-57f41407-moex-110-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '偵查中經檢察官訊問後，若未向法院聲請羈押被告，則檢察官不得為下列何種處置？', '["具保", "限制住居", "命繳納罰金", "直接釋放"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "160e5bc9c84a", "answer_pdf_sha1": "7aed6d4ac3f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
